sections.code_example:
person = {"name": "Alice", "age": 30, "city": "Paris"}

print(person.keys())
print(person.values())
print(person.items())

# Iterating keys
for key in person.keys():
    print(key)

# Iterating key-value pairs
for k, v in person.items():
    print(k, ":", v)

company = {
    "name": "Acme",
    "address": {
        "city": "Springfield",
        "zip": "12345"
    }
}

# Accessing nested values
print(company["name"])                   # Acme
print(company["address"]["city"])        # Springfield

# Updating a nested value
company["address"]["zip"] = "99999"
print(company["address"]["zip"])

